import{_ as t,o as n,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"103. Undergraduate Employment Models","description":"","frontmatter":{"title":"103. Undergraduate Employment Models","eba":"Mental Health Services 2024-2028","topics":["preliminary","definitions","education-pd"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/classification-staffing/103-undergraduate-employment-models.md","filePath":"ebas/mental-health/rpn-pen-mho/classification-staffing/103-undergraduate-employment-models.md"}'),i={name:"ebas/mental-health/rpn-pen-mho/classification-staffing/103-undergraduate-employment-models.md"};function s(a,e,l,p,d,g){return n(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_103-undergraduate-employment-models" tabindex="-1">103. Undergraduate Employment Models <a class="header-anchor" href="#_103-undergraduate-employment-models" aria-label="Permalink to &quot;103. Undergraduate Employment Models&quot;">​</a></h1><p><strong>103.1</strong> Registered Undergraduate Student of Nursing (RUSON)</p><p><strong>(a)</strong> Definition A Registered Undergraduate Student of Nursing or RUSON for the purposes of this clause is a person currently enrolled at a university to undertake undergraduate nursing study, who is registered with AHPRA as a student nurse,</p><p>and who at commencement, has successfully completed not less than twelve months of the Bachelor of Nursing Degree.</p><p><strong>(b)</strong> Implementation of Registered Undergraduate Student of Nursing Employment Model By agreement between the Employer and the Unions, an Employer may implement a Registered Undergraduate Student of Nursing Employment Model. It is at the discretion of each Employer as to whether they participate in the Registered Undergraduate Student of Nursing Employment Model.</p><p><strong>(c)</strong> Employment of RUSONs</p><p><strong>(i)</strong> RUSON will be employed on a fixed term basis or engaged on a casual basis.</p><p><strong>(ii)</strong> The RUSON must at all times work under the delegation and supervision of a Registered Nurse in accordance with a documented position description that is appropriate having regard to the level of education completed.</p><p><strong>(iii)</strong> RUSONs will not be given sole patient allocation but instead work with one or more nurses in the provision of care to a group of patients.</p><p><strong>(iv)</strong> In order to balance the RUSONs academic obligations and the needs of the Employer, the rostered work of students will be in shifts of not less than four hours on day or evening shifts, Monday to Sunday.</p><p><strong>(v)</strong> The RUSON will not work in ICA (however titled).</p><p><strong>(d)</strong> Termination of Employment</p><p><strong>(i)</strong> Employment will conclude: <strong>(A)</strong> from when the Employee terminates their employment <strong>(B)</strong> from when the Employer terminates the employment in accordance with this Agreement, <strong>(C)</strong> on being granted registration as a Registered Nurse unless the Employee, Employer and the Unions agree in writing to continue the employment for a short period of time to cover the period between registration and commencement of a graduate or similar program; or <strong>(D)</strong> when the Employee withdraws, defers from or fails their undergraduate degree. <strong>(E)</strong> In the case of a casual, in accordance with sub-<a href="/eba/ebas/mental-health/common-terms/employment-types/25-modes-of-employment.html">clause 25</a> (Casual Employment).</p><p><strong>(e)</strong> Rate of pay for RUSONs</p><p><strong>(i)</strong> Nothing in this subclause impacts the pay rate of a RUSON/PQRN employed as such at the commencement of the Agreement.</p><p><strong>(ii)</strong> Other than described in 103.1(e)(i)a RUSON will be paid on the following basis: Percentage of RPN Grade 2 Year 1 rate Year of employment as a RUSON of pay set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> RUSON 81.5%</p><p><strong>(f)</strong> Other terms and conditions for RUSONs</p><p>All other terms and conditions of employment will be those applying to a Registered Psychiatric Nurse under this Agreement except where this clause explicitly says otherwise.</p><p><strong>(g)</strong> Continuity of service Continuity of Service as a Registered Nurse will include any period of service in the program, provided any gap between employment as a student and commencement of employment as a Registered Nurse is less than twelve months.</p><p><strong>(h)</strong> Working Party</p><p><strong>(i)</strong> At the request of either Union, a Working Party will be established comprising representatives of the Unions, the Employer and, if practicable, the participating University/s.</p><p><strong>(ii)</strong> The Working Party will, prior to commencement of the model, agree on: <strong>(A)</strong> the participating wards/units <strong>(B)</strong> ensure the RUSON works within the Position Description, the Core activity list, and the Exclusion List <strong>(C)</strong> education and training of registered and enrolled nurses regarding the new role; and <strong>(D)</strong> the terms of the evaluation of the program.</p><p><strong>103.2</strong> Enrolled Nurse Pre-Qualification Employment Model (PQEN)</p><p><strong>(a)</strong> Enrolled Nurse Pre-Qualification Employment Model Definition A Pre-Qualification Enrolled Nurse (PQEN) for the purposes of this clause is a person currently enrolled at a TAFE or RTO to undertake diploma of nursing study, who is registered with AHPRA as a student nurse.</p><p><strong>(b)</strong> Implementation of Enrolled Nurse Pre-Qualification Employment Model By agreement between the Employer and the Unions, an Employer may implement a Pre-Qualification Enrolled Nurse Employment Model. It is at the discretion of each Employer as to whether they participate in the model.</p><p><strong>(c)</strong> Nothing in this sub-clause impacts the pay rate of an existing Pre-Qualified Enrolled Nurse (PQEN) employed as such at the commencement of the Agreement.</p><p><strong>(d)</strong> Employment of PQENs</p><p><strong>(i)</strong> PQEN participants will be employed on a fixed term basis and employment will conclude: <strong>(A)</strong> when the Employee terminates their employment <strong>(B)</strong> on being granted registration as an Enrolled Nurse unless the Employee, Employer and the Unions agree in writing to continue the employment for a short period of time to cover the period between registration and commencement of a graduate or similar program; or <strong>(C)</strong> when the Employee withdraws, defers from or fails their diploma.</p><p><strong>(ii)</strong> The number of student nurses utilised will not exceed one student per ward, per shift, and one additional student nurse may be utilised where the ward exceeds 30 beds by 10% or more.</p><p><strong>(iii)</strong> PQEN Employees will have performance appraisals conducted in accordance with hospital policy.</p><p><strong>(iv)</strong> In order to balance the PQENs academic obligations and the needs of the Employer, the rostered work of students will be in shifts of not less than four hours on day or evening shifts, Monday to Sunday.</p><p><strong>(v)</strong> PQENs will be delegated activities and aspects of care by a Registered Nurse and supervised in providing the delegated activity by the Registered Nurse. The PQEN must at all times work under the delegation and supervision of the Registered Nurse.</p><p><strong>(vi)</strong> PQENs will not be given sole patient allocation but instead work with one or more nurses in the provision of care to a group of patients.</p><p><strong>(vii)</strong> The PQEN will not work in HDU/ICA (however titled).</p><p><strong>(e)</strong> Rate of pay for PQENs</p><p><strong>(i)</strong> A PQEN will be paid at the same rate as the RUSON.</p><p><strong>(f)</strong> Other terms and conditions for PQENs All other terms and conditions of employment will be those applying to an Enrolled Nurse under this Agreement except where this clause explicitly says otherwise.</p><p><strong>(g)</strong> Continuity of service Continuity of Service as an Enrolled Nurse will include any period of service in the program, provided any gap between employment as a student and commencement of employment an Enrolled Nurse is less than twelve months.</p><p><strong>(h)</strong> Working Party</p><p><strong>(i)</strong> At the request of either Union, a Working Party will be established comprising representatives of the Unions, the Employer, Department of Health and, if practicable, the participating University/s.</p><p><strong>(ii)</strong> The Working Party will, prior to commencement of the model, agree on: <strong>(A)</strong> the participating wards/units; <strong>(B)</strong> ensure the PQEN works within the Position Description, the Core activity list, and the Exclusion List; <strong>(C)</strong> education and training of registered and enrolled nurses regarding the new role; and <strong>(D)</strong> the terms of the evaluation of the program.</p><p><strong>103.3</strong> Nursing Indigenous Health Cadetship</p><p><strong>(a)</strong> An Indigenous Nursing Cadet refers to an individual who identifies as an Aboriginal and/or Torres Strait Islander person and who is enrolled in a Bachelor of Nursing course and is employed in an Indigenous Nursing Cadetship program.</p><p><strong>(b)</strong> Indigenous Nursing Cadets must have progressed beyond the first year of their studies and be maintaining a pass grade in all subjects.</p><p><strong>(c)</strong> The cadetship program for mental health nursing includes the delivery of supportive structures within the organisation and a minimum of eight weeks (40 shifts) equivalent full-time paid work placement component. In a hospital setting, the role can include tasks such as assisting with patients’ activities of daily living, providing wellbeing support through communication, helping maintain a safe and clear environment and observing clinical procedures and therapeutic interventions</p><p><strong>(d)</strong> Each Indigenous Nursing Cadet should be assigned a coordinator, a clinical supervisor and a cultural mentor. These three roles may be undertaken by the same individual, as per the Aboriginal graduate and cadetship programs: An implementation guide for Victorian public health services document issued by the Victorian Government.</p><p><strong>(e)</strong> During the cadetship, Indigenous Nursing Cadets will:</p><p><strong>(i)</strong> receive income while studying</p><p><strong>(ii)</strong> become familiar with a potential future place of employment</p><p><strong>(iii)</strong> receive skill consolidation through practice</p><p><strong>(iv)</strong> receive mentoring by Aboriginal and/or Torres Strait Islander staff or non-Aboriginal staff already working in the health service</p><p><strong>(v)</strong> create a formation of professional networks</p><p><strong>(vi)</strong> build personal and professional growth and confidence</p><p><strong>(vii)</strong> receive opportunities for professional development / education</p><p><strong>(viii)</strong> build career confidence and opportunities; and</p><p><strong>(ix)</strong> receive opportunities to link with peers through peer support networks, shared study days, and visits with Elders to ensure culturally safe professional development opportunities.</p><p><strong>(f)</strong> Before implementing the Indigenous Nursing Cadetship and/or a graduate program, the relevant health service should ensure the following factors are in place in order to facilitate cultural responsiveness and safety:</p><p><strong>(i)</strong> demonstrated commitment to establishing an Aboriginal graduate and/or cadetship program</p><p><strong>(ii)</strong> communication to all staff about the Aboriginal graduate and/or cadetship programs</p><p><strong>(iii)</strong> a strong supportive culture of training and professional development for staff</p><p><strong>(iv)</strong> established governance structures and arrangements required to support an Aboriginal graduate and/or cadetship program</p><p><strong>(v)</strong> developed relationships with the local Aboriginal and/or Torres Strait Islander community and Aboriginal and/or Torres Strait Islander organisations</p><p><strong>(vi)</strong> identified and engaged relevant stakeholders required to support an Aboriginal graduate and/or cadetship program</p><p><strong>(vii)</strong> working to ensure that cultural safety is a priority in building the capacity of the workforce and health service that will be supporting the Aboriginal cadet or graduate</p><p><strong>(viii)</strong> providing appropriate staffing to support the delivery of the Aboriginal graduate and/or cadetship programs; and</p><p><strong>(ix)</strong> identified an evaluation strategy for the program.</p>',66)])])}const u=t(i,[["render",s]]);export{m as __pageData,u as default};
